'use client';

import type { CustomCellRendererProps } from 'ag-grid-react';
import { Check, X } from 'lucide-react';

import { cn } from '../../../utils';

export interface BooleanCellProps<TData = unknown>
  extends CustomCellRendererProps<TData, boolean> {
  /** Custom icon for true state */
  trueIcon?: React.ReactNode;
  /** Custom icon for false state */
  falseIcon?: React.ReactNode;
  /** Text for true state (if no icon) */
  trueText?: string;
  /** Text for false state (if no icon) */
  falseText?: string;
  /** Whether to color the icons (green/red) */
  colored?: boolean;
  /** Fallback for null/undefined */
  fallback?: React.ReactNode;
}

/**
 * AG-Grid cell renderer for boolean columns.
 * Shows check/X icons or custom content.
 *
 * @example
 * ```tsx
 * // Basic usage with colored icons
 * { field: 'isActive', cellRenderer: BooleanCell, cellRendererParams: { colored: true } }
 *
 * // With text instead of icons
 * {
 *   field: 'verified',
 *   cellRenderer: BooleanCell,
 *   cellRendererParams: {
 *     trueText: 'Yes',
 *     falseText: 'No',
 *   }
 * }
 * ```
 */
export function BooleanCell<TData = unknown>({
  value,
  trueIcon,
  falseIcon,
  trueText,
  falseText,
  colored = false,
  fallback = null,
}: BooleanCellProps<TData>) {
  if (value == null) {
    return <>{fallback}</>;
  }

  // Text mode
  if (trueText || falseText) {
    return (
      <span
        className={cn(
          colored && value && 'text-[var(--status-success)]',
          colored && !value && 'text-[var(--status-danger)]'
        )}
      >
        {value ? (trueText ?? 'Yes') : (falseText ?? 'No')}
      </span>
    );
  }

  // Icon mode
  const TrueContent = trueIcon ?? (
    <Check
      className={cn('h-4 w-4', colored && 'text-[var(--status-success)]')}
    />
  );
  const FalseContent = falseIcon ?? (
    <X className={cn('h-4 w-4', colored && 'text-[var(--status-danger)]')} />
  );

  return <>{value ? TrueContent : FalseContent}</>;
}
