'use client';

import type { CustomCellRendererProps } from 'ag-grid-react';

import { cn } from '../../../utils';
import { formatCurrency, type FormatNumberOptions } from '../../../utils';

export interface CurrencyCellProps<TData = unknown>
  extends CustomCellRendererProps<TData, number> {
  /** Format options */
  formatOptions?: Omit<FormatNumberOptions, 'style'>;
  /** Show negative values in red */
  colorNegative?: boolean;
  /** Fallback text for null values */
  fallback?: string;
}

/**
 * AG-Grid cell renderer for currency columns.
 * Provides consistent currency formatting across all grids.
 *
 * @example
 * ```tsx
 * // Basic usage
 * { field: 'amount', cellRenderer: CurrencyCell }
 *
 * // With custom format and negative coloring
 * {
 *   field: 'balance',
 *   cellRenderer: CurrencyCell,
 *   cellRendererParams: {
 *     formatOptions: { currency: 'EUR', locale: 'de-DE' },
 *     colorNegative: true,
 *   }
 * }
 * ```
 */
export function CurrencyCell<TData = unknown>({
  value,
  formatOptions,
  colorNegative = false,
  fallback = '',
}: CurrencyCellProps<TData>) {
  if (value == null) {
    return <span className="text-muted-foreground">{fallback}</span>;
  }

  const formatted = formatCurrency(value, formatOptions);
  const isNegative = value < 0;

  return (
    <span
      className={cn(
        'tabular-nums',
        colorNegative && isNegative && 'text-[var(--status-danger)]'
      )}
    >
      {formatted}
    </span>
  );
}
