'use client';

import type { CustomCellRendererProps } from 'ag-grid-react';
import { MoreHorizontal } from 'lucide-react';

import { Button } from '../../ui/button';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '../../ui/dropdown-menu';

export interface ActionItem<TData = unknown> {
  /** Action label */
  label: string;
  /** Action icon */
  icon?: React.ReactNode;
  /** Click handler */
  onClick: (data: TData) => void;
  /** Whether to show a separator before this item */
  separator?: boolean;
  /** Whether the action is destructive */
  destructive?: boolean;
  /** Whether the action is disabled */
  disabled?: boolean | ((data: TData) => boolean);
  /** Whether to hide this action */
  hidden?: boolean | ((data: TData) => boolean);
}

export interface ActionsCellProps<TData = unknown>
  extends CustomCellRendererProps<TData> {
  /** List of actions to show in the dropdown */
  actions: ActionItem<TData>[];
  /** Accessible label for the menu trigger */
  triggerLabel?: string;
}

/**
 * AG-Grid cell renderer for action columns.
 * Shows a dropdown menu with configurable actions.
 *
 * @example
 * ```tsx
 * {
 *   field: 'actions',
 *   headerName: '',
 *   width: 60,
 *   cellRenderer: ActionsCell,
 *   cellRendererParams: {
 *     actions: [
 *       { label: 'Edit', icon: <Pencil />, onClick: (row) => editRow(row) },
 *       { label: 'Delete', onClick: (row) => deleteRow(row), destructive: true, separator: true },
 *     ],
 *   }
 * }
 * ```
 */
export function ActionsCell<TData = unknown>({
  data,
  actions,
  triggerLabel = 'Actions',
}: ActionsCellProps<TData>) {
  if (!data) return null;

  // Filter out hidden actions
  const visibleActions = actions.filter((action) => {
    if (action.hidden === true) return false;
    if (typeof action.hidden === 'function') return !action.hidden(data);
    return true;
  });

  if (visibleActions.length === 0) return null;

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="ghost" size="icon" className="h-8 w-8">
          <MoreHorizontal className="h-4 w-4" />
          <span className="sr-only">{triggerLabel}</span>
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end">
        {visibleActions.map((action, index) => {
          const isDisabled =
            typeof action.disabled === 'function'
              ? action.disabled(data)
              : action.disabled;

          return (
            <div key={action.label}>
              {action.separator && index > 0 && <DropdownMenuSeparator />}
              <DropdownMenuItem
                onClick={() => action.onClick(data)}
                disabled={isDisabled}
                className={action.destructive ? 'text-destructive' : undefined}
              >
                {action.icon && (
                  <span className="mr-2 h-4 w-4">{action.icon}</span>
                )}
                {action.label}
              </DropdownMenuItem>
            </div>
          );
        })}
      </DropdownMenuContent>
    </DropdownMenu>
  );
}
