'use client';

import type { CustomCellRendererProps } from 'ag-grid-react';

import { cn } from '../../../utils';
import { formatPercent, type FormatNumberOptions } from '../../../utils';

export interface PercentCellProps<TData = unknown>
  extends CustomCellRendererProps<TData, number> {
  /** Format options */
  formatOptions?: Omit<FormatNumberOptions, 'style'>;
  /** Show a visual bar behind the percentage */
  showBar?: boolean;
  /** Color the bar based on value (green for high, red for low) */
  colorBar?: boolean;
  /** Value is already in percentage form (0-100) vs decimal (0-1) */
  isPercentage?: boolean;
  /** Fallback text for null values */
  fallback?: string;
}

/**
 * AG-Grid cell renderer for percentage columns.
 * Optionally shows a visual bar representation.
 *
 * @example
 * ```tsx
 * // Basic usage (decimal value 0-1)
 * { field: 'rate', cellRenderer: PercentCell }
 *
 * // With visual bar (percentage value 0-100)
 * {
 *   field: 'progress',
 *   cellRenderer: PercentCell,
 *   cellRendererParams: {
 *     showBar: true,
 *     colorBar: true,
 *     isPercentage: true,
 *   }
 * }
 * ```
 */
export function PercentCell<TData = unknown>({
  value,
  formatOptions,
  showBar = false,
  colorBar = false,
  isPercentage = false,
  fallback = '',
}: PercentCellProps<TData>) {
  if (value == null) {
    return <span className="text-muted-foreground">{fallback}</span>;
  }

  // Convert to decimal for formatting (formatPercent expects 0-1)
  const decimalValue = isPercentage ? value / 100 : value;
  const percentValue = isPercentage ? value : value * 100;

  const formatted = formatPercent(decimalValue, formatOptions);

  if (!showBar) {
    return <span className="tabular-nums">{formatted}</span>;
  }

  // Determine bar color based on value
  const barColor = colorBar
    ? percentValue >= 70
      ? 'bg-[var(--status-success)]'
      : percentValue >= 40
        ? 'bg-[var(--status-warning)]'
        : 'bg-[var(--status-danger)]'
    : 'bg-primary';

  return (
    <div className="flex items-center gap-2">
      <div className="relative h-2 w-16 overflow-hidden rounded-full bg-muted">
        <div
          className={cn('absolute inset-y-0 left-0 rounded-full', barColor)}
          style={{ width: `${Math.min(100, Math.max(0, percentValue))}%` }}
        />
      </div>
      <span className="tabular-nums text-xs">{formatted}</span>
    </div>
  );
}
