'use client';

import { useCallback, useMemo, useRef } from 'react';
import { AgGridReact } from 'ag-grid-react';
import {
  AllCommunityModule,
  ModuleRegistry,
  themeQuartz,
  type ColDef,
  type GridApi,
  type GridReadyEvent,
  type RowClickedEvent,
  type SelectionChangedEvent,
} from 'ag-grid-community';

import { cn } from '../../utils';
import type { DataGridProps, DataGridDensity } from './types';

// Register AG-Grid Community modules
ModuleRegistry.registerModules([AllCommunityModule]);

/**
 * Row height by density
 */
const DENSITY_ROW_HEIGHT: Record<DataGridDensity, number> = {
  compact: 40,
  comfortable: 48,
  spacious: 56,
};

/**
 * Header height by density
 */
const DENSITY_HEADER_HEIGHT: Record<DataGridDensity, number> = {
  compact: 40,
  comfortable: 48,
  spacious: 56,
};

/**
 * Tarva UI Grid theme using Quartz base.
 * Maps to CSS custom properties for light/dark mode support.
 */
const tarvaGridTheme = themeQuartz.withParams({
  // Use CSS custom properties for theming
  accentColor: 'var(--primary)',
  backgroundColor: 'var(--card)',
  foregroundColor: 'var(--card-foreground)',
  borderColor: 'var(--border)',
  headerBackgroundColor: 'var(--muted)',
  headerTextColor: 'var(--muted-foreground)',
  oddRowBackgroundColor: 'var(--card)',
  rowHoverColor: 'var(--accent)',
  selectedRowBackgroundColor: 'var(--accent)',

  // Typography
  fontFamily: 'var(--font-sans, ui-sans-serif, system-ui, sans-serif)',
  headerFontFamily: 'var(--font-sans, ui-sans-serif, system-ui, sans-serif)',
  headerFontSize: 13,
  headerFontWeight: 500,

  // Borders
  wrapperBorder: true,
  wrapperBorderRadius: 8,
  headerRowBorder: false,
});

/**
 * Default column definition
 */
const defaultColDef: ColDef = {
  filter: true,
  sortable: true,
  resizable: true,
  suppressHeaderContextMenu: true,
  suppressHeaderMenuButton: true,
  cellStyle: { display: 'flex', alignItems: 'center' },
};

/**
 * DataGrid component - @tarva/ui themed AG-Grid wrapper
 *
 * Features:
 * - Tarva UI theme integration (light/dark mode)
 * - Density variants (compact, comfortable, spacious)
 * - Selection modes (none, single, multiple)
 * - Quick filter support
 * - CSV export support
 * - Included cell renderers for common data types
 *
 * @example
 * ```tsx
 * import { DataGrid, StatusCell, CurrencyCell } from '@tarva/ui/data-grid';
 *
 * <DataGrid
 *   rowData={data}
 *   columnDefs={[
 *     { field: 'name', headerName: 'Name' },
 *     { field: 'status', cellRenderer: StatusCell },
 *     { field: 'amount', cellRenderer: CurrencyCell },
 *   ]}
 *   density="comfortable"
 *   selectionMode="multiple"
 *   onSelectionChange={(rows) => setSelected(rows)}
 * />
 * ```
 */
export function DataGrid<TData = unknown>({
  className,
  defaultColDef: customColDef,
  density = 'comfortable',
  selectionMode = 'none',
  showSelectionCheckbox = true,
  quickFilterText,
  enableExport: _enableExport = false,
  exportFileName = 'export',
  onRowClick,
  onSelectionChange,
  gridContext,
  loading = false,
  emptyMessage = 'No data to display',
  onGridReady,
  domLayout = 'autoHeight',
  ...props
}: DataGridProps<TData>) {
  const gridRef = useRef<AgGridReact<TData>>(null);
  const gridApiRef = useRef<GridApi<TData> | null>(null);

  // Merge column definitions
  const mergedColDef = useMemo<ColDef<TData>>(
    () =>
      ({
        ...defaultColDef,
        ...customColDef,
      }) as ColDef<TData>,
    [customColDef]
  );

  // Get row selection config
  const rowSelection = useMemo(() => {
    if (selectionMode === 'none') return undefined;
    return {
      mode: selectionMode === 'single' ? 'singleRow' : 'multiRow',
      checkboxes: showSelectionCheckbox,
    } as const;
  }, [selectionMode, showSelectionCheckbox]);

  // Handle grid ready
  const handleGridReady = useCallback(
    (event: GridReadyEvent<TData>) => {
      gridApiRef.current = event.api;
      onGridReady?.(event);
    },
    [onGridReady]
  );

  // Handle row click
  const handleRowClicked = useCallback(
    (event: RowClickedEvent<TData>) => {
      // Skip if clicking on a button or interactive element
      const target = event.event?.target as HTMLElement | null;
      if (target?.closest('button, a, input, [role="menuitem"]')) {
        return;
      }
      if (onRowClick && event.data) {
        onRowClick(event.data, event);
      }
    },
    [onRowClick]
  );

  // Handle selection change
  const handleSelectionChanged = useCallback(
    (event: SelectionChangedEvent<TData>) => {
      if (onSelectionChange) {
        const selectedRows = event.api.getSelectedRows();
        onSelectionChange(selectedRows);
      }
    },
    [onSelectionChange]
  );

  // Export function (can be called via ref)
  const exportToCsv = useCallback(() => {
    gridApiRef.current?.exportDataAsCsv({
      fileName: `${exportFileName}.csv`,
    });
  }, [exportFileName]);

  // Expose export function via context
  const context = useMemo(
    () => ({
      ...gridContext,
      exportToCsv,
    }),
    [gridContext, exportToCsv]
  );

  // Determine layout classes
  const isNormalLayout = domLayout === 'normal';

  return (
    <div
      data-slot="data-grid"
      className={cn(
        'w-full',
        !isNormalLayout && 'pb-4',
        isNormalLayout && 'h-full',
        className
      )}
    >
      <AgGridReact<TData>
        ref={gridRef}
        theme={tarvaGridTheme}
        defaultColDef={mergedColDef}
        rowHeight={DENSITY_ROW_HEIGHT[density]}
        headerHeight={DENSITY_HEADER_HEIGHT[density]}
        rowSelection={rowSelection}
        domLayout={domLayout}
        animateRows
        suppressCellFocus
        suppressHorizontalScroll={false}
        suppressDragLeaveHidesColumns
        suppressMovableColumns={false}
        quickFilterText={quickFilterText}
        loading={loading}
        overlayNoRowsTemplate={`<span class="text-muted-foreground">${emptyMessage}</span>`}
        context={context}
        onGridReady={handleGridReady}
        onRowClicked={handleRowClicked}
        onSelectionChanged={handleSelectionChanged}
        {...props}
      />
    </div>
  );
}

/**
 * Re-export the theme for custom usage
 */
export { tarvaGridTheme };
