'use client';

import type { CustomCellRendererProps } from 'ag-grid-react';

import { formatDate, type FormatDateOptions } from '../../../utils';

export interface DateCellProps<TData = unknown>
  extends CustomCellRendererProps<TData, string | Date | number> {
  /** Date format options */
  formatOptions?: FormatDateOptions;
  /** Fallback text for null/invalid dates */
  fallback?: string;
}

/**
 * AG-Grid cell renderer for date columns.
 * Provides consistent date formatting across all grids.
 *
 * @example
 * ```tsx
 * // Basic usage - defaults to medium format
 * { field: 'createdAt', cellRenderer: DateCell }
 *
 * // With custom format
 * {
 *   field: 'createdAt',
 *   cellRenderer: DateCell,
 *   cellRendererParams: {
 *     formatOptions: { format: 'long', includeTime: true },
 *     fallback: 'Not set',
 *   }
 * }
 * ```
 */
export function DateCell<TData = unknown>({
  value,
  formatOptions,
  fallback = '',
}: DateCellProps<TData>) {
  if (value == null) return <span className="text-muted-foreground">{fallback}</span>;

  const formatted = formatDate(value, formatOptions);

  return <span className="tabular-nums">{formatted}</span>;
}
