'use client';

import type { CustomCellRendererProps } from 'ag-grid-react';

import { StatusBadge } from '../../ui/status-badge';
import type { StatusCategory, StatusVariant } from '../../ui/status-badge';

export interface StatusCellProps<TData = unknown>
  extends CustomCellRendererProps<TData, string> {
  /** Map raw values to status categories */
  categoryMap?: Record<string, StatusCategory>;
  /** Map raw values to custom labels */
  labelMap?: Record<string, string>;
  /** Display variant */
  variant?: StatusVariant;
}

/**
 * AG-Grid cell renderer for status columns.
 * Uses StatusBadge for consistent status display across all grids.
 *
 * @example
 * ```tsx
 * // Basic usage - value is used as status key
 * { field: 'status', cellRenderer: StatusCell }
 *
 * // With custom mapping
 * {
 *   field: 'status',
 *   cellRenderer: StatusCell,
 *   cellRendererParams: {
 *     categoryMap: { trial: 'warning', suspended: 'danger' },
 *     labelMap: { trial: 'Trial Period' },
 *   }
 * }
 * ```
 */
export function StatusCell<TData = unknown>({
  value,
  categoryMap,
  labelMap,
  variant = 'dot',
}: StatusCellProps<TData>) {
  if (value == null) return null;

  const category = categoryMap?.[value];
  const label = labelMap?.[value];

  return (
    <StatusBadge
      status={value}
      category={category}
      label={label}
      variant={variant}
    />
  );
}
