/**
 * AG-Grid value formatters for @tarva/ui DataGrid.
 *
 * These can be used directly in column definitions:
 * @example
 * { field: 'amount', valueFormatter: currencyValueFormatter }
 */

import {
  formatCurrency,
  formatDate,
  formatNumber,
  formatPercent,
  type FormatDateOptions,
  type FormatNumberOptions,
} from '../../utils';

interface ValueFormatterParams {
  value: unknown;
}

/**
 * Currency value formatter for AG-Grid.
 * @example { valueFormatter: currencyValueFormatter }
 */
export function currencyValueFormatter(params: ValueFormatterParams): string {
  if (params.value == null) return '';
  return formatCurrency(params.value as number);
}

/**
 * Create a currency formatter with custom options.
 * @example { valueFormatter: createCurrencyFormatter({ currency: 'EUR' }) }
 */
export function createCurrencyFormatter(
  options?: Omit<FormatNumberOptions, 'style'>
) {
  return (params: ValueFormatterParams): string => {
    if (params.value == null) return '';
    return formatCurrency(params.value as number, options);
  };
}

/**
 * Date value formatter for AG-Grid.
 * @example { valueFormatter: dateValueFormatter }
 */
export function dateValueFormatter(params: ValueFormatterParams): string {
  if (!params.value) return '';
  return formatDate(params.value as Date | string | number);
}

/**
 * Create a date formatter with custom options.
 * @example { valueFormatter: createDateFormatter({ format: 'long', includeTime: true }) }
 */
export function createDateFormatter(options?: FormatDateOptions) {
  return (params: ValueFormatterParams): string => {
    if (!params.value) return '';
    return formatDate(params.value as Date | string | number, options);
  };
}

/**
 * Percentage value formatter for AG-Grid (expects decimal 0-1).
 * @example { valueFormatter: percentValueFormatter }
 */
export function percentValueFormatter(params: ValueFormatterParams): string {
  if (params.value == null) return '';
  return formatPercent(params.value as number);
}

/**
 * Create a percent formatter with custom options.
 * @example { valueFormatter: createPercentFormatter({ maximumFractionDigits: 2 }) }
 */
export function createPercentFormatter(
  options?: Omit<FormatNumberOptions, 'style'>
) {
  return (params: ValueFormatterParams): string => {
    if (params.value == null) return '';
    return formatPercent(params.value as number, options);
  };
}

/**
 * Number value formatter for AG-Grid.
 * @example { valueFormatter: numberValueFormatter }
 */
export function numberValueFormatter(params: ValueFormatterParams): string {
  if (params.value == null) return '';
  return formatNumber(params.value as number);
}

/**
 * Create a number formatter with custom options.
 * @example { valueFormatter: createNumberFormatter({ maximumFractionDigits: 2 }) }
 */
export function createNumberFormatter(options?: FormatNumberOptions) {
  return (params: ValueFormatterParams): string => {
    if (params.value == null) return '';
    return formatNumber(params.value as number, options);
  };
}

/**
 * Boolean value formatter for AG-Grid.
 * @example { valueFormatter: booleanValueFormatter }
 */
export function booleanValueFormatter(params: ValueFormatterParams): string {
  if (params.value == null) return '';
  return params.value ? 'Yes' : 'No';
}

/**
 * Create a boolean formatter with custom labels.
 * @example { valueFormatter: createBooleanFormatter('Active', 'Inactive') }
 */
export function createBooleanFormatter(trueLabel = 'Yes', falseLabel = 'No') {
  return (params: ValueFormatterParams): string => {
    if (params.value == null) return '';
    return params.value ? trueLabel : falseLabel;
  };
}
